const LangCtx = createContext({ lang: "de", t: T.de });
const useLang = () => useContext(LangCtx);

function useInView(threshold = 0.1) {
  const ref = useRef(null);
  const [inView, setInView] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setInView(true); }, { threshold });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return [ref, inView];
}

function Reveal({ children, delay = 0, style = {} }) {
  const [ref, inView] = useInView();
  return (
    <div ref={ref} style={{
      opacity: inView ? 1 : 0,
      transform: inView ? "translateY(0)" : "translateY(20px)",
      transition: `opacity 0.55s ease ${delay}s, transform 0.55s ease ${delay}s`,
      ...style,
    }}>{children}</div>
  );
}

function Divider() {
  return <div style={{ height: "1px", background: BORDER }} />;
}

function Lightbox({ src, onClose }) {
  useEffect(() => {
    const handler = (e) => { if (e.key === "Escape") onClose(); };
    document.addEventListener("keydown", handler);
    document.body.style.overflow = "hidden";
    return () => {
      document.removeEventListener("keydown", handler);
      document.body.style.overflow = "";
    };
  }, [onClose]);
  return (
    <div onClick={onClose} style={{
      position: "fixed", inset: 0, zIndex: 999,
      background: "rgba(0,0,0,0.92)",
      display: "flex", alignItems: "center", justifyContent: "center",
      padding: "2rem", cursor: "zoom-out",
      animation: "fadeIn 0.2s ease",
    }}>
      <img src={src} alt="Vergrößert" onClick={e => e.stopPropagation()} style={{
        maxWidth: "100%", maxHeight: "90vh", objectFit: "contain",
        borderRadius: "8px", boxShadow: "0 32px 80px rgba(0,0,0,0.8)",
        animation: "scaleIn 0.2s ease", cursor: "default",
      }} />
      <button onClick={onClose} style={{
        position: "fixed", top: "1.5rem", right: "1.5rem",
        background: "rgba(255,255,255,0.1)", border: "1px solid rgba(255,255,255,0.15)",
        borderRadius: "50%", width: "40px", height: "40px",
        color: "#fff", fontSize: "1rem", cursor: "pointer",
        display: "flex", alignItems: "center", justifyContent: "center",
        transition: "background 0.2s",
      }}
        onMouseEnter={e => e.currentTarget.style.background = "rgba(255,255,255,0.2)"}
        onMouseLeave={e => e.currentTarget.style.background = "rgba(255,255,255,0.1)"}
      >✕</button>
    </div>
  );
}

function LangToggle({ lang, setLang }) {
  return (
    <button onClick={() => setLang(l => l === "de" ? "en" : "de")} style={{
      fontFamily: "inherit", fontSize: "0.72rem",
      padding: "0.3rem 0.9rem", borderRadius: "4px",
      border: `1px solid ${BORDER}`,
      background: "rgba(255,255,255,0.04)", color: "rgba(255,255,255,0.5)",
      cursor: "pointer", transition: "all 0.2s",
    }}
      onMouseEnter={e => { e.currentTarget.style.borderColor = "rgba(255,255,255,0.25)"; e.currentTarget.style.color = "#fff"; }}
      onMouseLeave={e => { e.currentTarget.style.borderColor = BORDER; e.currentTarget.style.color = "rgba(255,255,255,0.5)"; }}
    >
      {lang === "de" ? "🇬🇧 EN" : "🇩🇪 DE"}
    </button>
  );
}

