function SectionHeader({ label, title }) {
  return (
    <Reveal style={{ marginBottom: "3rem" }}>
      <p style={{ fontFamily: "'Outfit', sans-serif", fontSize: "0.75rem", fontWeight: 500, color: ACCENT, letterSpacing: "0.1em", textTransform: "uppercase", margin: "0 0 0.6rem" }}>{label}</p>
      <h2 style={{ fontFamily: "'Outfit', sans-serif", fontSize: "clamp(1.75rem,3.5vw,2.5rem)", fontWeight: 700, color: "#fff", margin: 0, letterSpacing: "-0.02em" }}>{title}</h2>
    </Reveal>
  );
}

function Projects() {
  const { t } = useLang();
  return (
    <section id="projects" style={{ padding: "0 clamp(1.5rem,8vw,8rem) 7rem" }}>
      <Divider />
      <div style={{ paddingTop: "5rem" }}>
        <SectionHeader label={t.sec_projects} title={t.sec_projects_sub} />
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(min(100%, 480px), 1fr))", gap: "1.5rem" }}>
          {t.projects.map((tp, i) => <ProjectCard key={i} tp={tp} meta={PROJECT_META[i]} index={i} />)}
        </div>
      </div>
    </section>
  );
}

function Skills() {
  const { t } = useLang();
  return (
    <section id="skills" style={{ padding: "0 clamp(1.5rem,8vw,8rem) 7rem" }}>
      <Divider />
      <div style={{ paddingTop: "5rem" }}>
        <SectionHeader label={t.sec_skills} title={t.sec_skills_sub} />
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(180px, 1fr))", gap: "2.5rem" }}>
          {t.skill_groups.map((group, gi) => (
            <Reveal key={group.g} delay={gi * 0.07}>
              <p style={{ fontFamily: "'Outfit', sans-serif", fontSize: "0.72rem", fontWeight: 600, color: ACCENT, letterSpacing: "0.1em", textTransform: "uppercase", margin: "0 0 1rem" }}>{group.g}</p>
              <div>
                {group.items.map(item => (
                  <div key={item} style={{ fontFamily: "'Outfit', sans-serif", fontSize: "0.9rem", color: "rgba(255,255,255,0.65)", padding: "0.5rem 0", borderBottom: `1px solid ${BORDER}` }}>
                    {item}
                  </div>
                ))}
              </div>
            </Reveal>
          ))}
        </div>
      </div>
    </section>
  );
}

function Contact() {
  const { t } = useLang();
  return (
    <section id="contact" style={{ padding: "0 clamp(1.5rem,8vw,8rem) 7rem" }}>
      <Divider />
      <div style={{ paddingTop: "5rem", maxWidth: "580px" }}>
        <SectionHeader label={t.sec_contact} title={t.contact_h} />
        <Reveal delay={0.1}>
          <p style={{ fontFamily: "'Outfit', sans-serif", fontSize: "1rem", color: "rgba(255,255,255,0.48)", lineHeight: 1.8, margin: "0 0 2rem" }}>{t.contact_sub}</p>
          <div style={{ display: "flex", flexDirection: "column", gap: "0.65rem" }}>
            {[
              { label: "mirco.schrammeck@gmail.com", href: "mailto:mirco.schrammeck@gmail.com", primary: true },
              { label: "github.com/Elvios97", href: "https://github.com/Elvios97", primary: false },
              { label: "linkedin.com/in/MircoSchrammeck", href: "https://linkedin.com/in/MircoSchrammeck", primary: false },
            ].map(item => (
              <a key={item.label} href={item.href} target={item.primary ? undefined : "_blank"} rel="noreferrer" style={{
                fontFamily: "'Outfit', sans-serif", fontSize: "0.9rem",
                padding: "0.85rem 1.5rem", borderRadius: "6px",
                textDecoration: "none", transition: "all 0.2s",
                display: "flex", alignItems: "center", gap: "0.5rem",
                ...(item.primary
                  ? { background: ACCENT, color: "#fff", fontWeight: 500 }
                  : { border: `1px solid ${BORDER}`, color: "rgba(255,255,255,0.55)" }
                ),
              }}
                onMouseEnter={e => {
                  if (item.primary) e.currentTarget.style.opacity = "0.85";
                  else { e.currentTarget.style.borderColor = "rgba(255,255,255,0.25)"; e.currentTarget.style.color = "#fff"; }
                }}
                onMouseLeave={e => {
                  if (item.primary) e.currentTarget.style.opacity = "1";
                  else { e.currentTarget.style.borderColor = BORDER; e.currentTarget.style.color = "rgba(255,255,255,0.55)"; }
                }}
              >{item.label}</a>
            ))}
          </div>
        </Reveal>
      </div>
    </section>
  );
}

function Footer({ t }) {
  return (
    <footer style={{ padding: "2rem clamp(1.5rem,8vw,8rem)", borderTop: `1px solid ${BORDER}` }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: "1rem" }}>
        <span style={{ fontFamily: "'Outfit', sans-serif", fontSize: "0.78rem", color: "rgba(255,255,255,0.22)" }}>{t.footer}</span>
        <div style={{ display: "flex", gap: "1.25rem" }}>
          {["PSM I", "PSPO I", "Fachinformatiker AE"].map(c => (
            <span key={c} style={{ fontFamily: "'Outfit', sans-serif", fontSize: "0.72rem", color: "rgba(255,255,255,0.2)" }}>{c}</span>
          ))}
        </div>
      </div>
    </footer>
  );
}

export default function Portfolio() {
  const [lang, setLang] = useState("de");
  const t = T[lang];
  return (
    <LangCtx.Provider value={{ lang, t }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Outfit:wght@400;500;600;700&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        html { scroll-behavior: smooth; }
        body { background: #0A0E1A; }
        ::-webkit-scrollbar { width: 3px; }
        ::-webkit-scrollbar-track { background: #0A0E1A; }
        ::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 2px; }
        @keyframes blink { 0%,100% { opacity:1; } 50% { opacity:0.3; } }
        @keyframes fadeIn { from { opacity:0; } to { opacity:1; } }
        @keyframes scaleIn { from { transform:scale(0.94); } to { transform:scale(1); } }
      `}</style>
      <div style={{ background: "#0A0E1A", minHeight: "100vh", color: "#fff" }}>
        <Navbar lang={lang} setLang={setLang} />
        <Hero />
        <Projects />
        <Skills />
        <Contact />
        <Footer t={t} />
      </div>
    </LangCtx.Provider>
  );
}
